620           if (AI && !contains(AI) &&
621               (!AccessGroup || !ContainsAccessGroup(AccessGroup)))
622             return false;
623         }
624       }
625 
626       if (MDNode *AccessGroup = I.getMetadata(LLVMContext::MD_access_group)) {
627         if (ContainsAccessGroup(AccessGroup))
628           continue;
629       }
630 
631       // The memory instruction can refer to the loop identifier metadata
632       // directly or indirectly through another list metadata (in case of
633       // nested parallel loops). The loop identifier metadata refers to
634       // itself so we can check both cases with the same routine.
635       MDNode *LoopIdMD =
636           I.getMetadata(LLVMContext::MD_mem_parallel_loop_access);
637 
638       if (!LoopIdMD)
639         return false;
640 
641       if (!llvm::is_contained(LoopIdMD->operands(), DesiredLoopIdMetadata))
642         return false;
643     }
644   }
645   return true;
646 }
