650 Loop::LocRange Loop::getLocRange() const {
651   // If we have a debug location in the loop ID, then use it.
652   if (MDNode *LoopID = getLoopID()) {
653     DebugLoc Start;
654     // We use the first DebugLoc in the header as the start location of the loop
655     // and if there is a second DebugLoc in the header we use it as end location
656     // of the loop.
657     for (const MDOperand &MDO : llvm::drop_begin(LoopID->operands())) {
658       if (DILocation *L = dyn_cast<DILocation>(MDO)) {
659         if (!Start)
660           Start = DebugLoc(L);
661         else
662           return LocRange(Start, DebugLoc(L));
663       }
664     }
665 
666     if (Start)
667       return LocRange(Start);
668   }
669 
670   // Try the pre-header first.
671   if (BasicBlock *PHeadBB = getLoopPreheader())
672     if (DebugLoc DL = PHeadBB->getTerminator()->getDebugLoc())
673       return LocRange(DL);
674 
675   // If we have no pre-header or there are no instructions with debug
676   // info in it, try the header.
677   if (BasicBlock *HeadBB = getHeader())
678     return LocRange(HeadBB->getTerminator()->getDebugLoc());
679 
680   return LocRange();
681 }
