707 /// Find the new parent loop for all blocks within the "unloop" whose last
708 /// backedges has just been removed.
709 class UnloopUpdater {
710   Loop &Unloop;
711   LoopInfo *LI;
712 
713   LoopBlocksDFS DFS;
714 
715   // Map unloop's immediate subloops to their nearest reachable parents. Nested
716   // loops within these subloops will not change parents. However, an immediate
717   // subloop's new parent will be the nearest loop reachable from either its own
718   // exits *or* any of its nested loop's exits.
719   DenseMap<Loop *, Loop *> SubloopParents;
720 
721   // Flag the presence of an irreducible backedge whose destination is a block
722   // directly contained by the original unloop.
723   bool FoundIB = false;
724 
725 public:
726   UnloopUpdater(Loop *UL, LoopInfo *LInfo) : Unloop(*UL), LI(LInfo), DFS(UL) {}
727 
728   void updateBlockParents();
729 
730   void removeBlocksFromAncestors();
731 
732   void updateSubloopParents();
733 
734 protected:
735   Loop *getNearestLoop(BasicBlock *BB, Loop *BBLoop);
736 };
737 } // end anonymous namespace
