739 /// Update the parent loop for all blocks that are directly contained within the
740 /// original "unloop".
741 void UnloopUpdater::updateBlockParents() {
742   if (Unloop.getNumBlocks()) {
743     // Perform a post order CFG traversal of all blocks within this loop,
744     // propagating the nearest loop from successors to predecessors.
745     LoopBlocksTraversal Traversal(DFS, LI);
746     for (BasicBlock *POI : Traversal) {
747 
748       Loop *L = LI->getLoopFor(POI);
749       Loop *NL = getNearestLoop(POI, L);
750 
751       if (NL != L) {
752         // For reducible loops, NL is now an ancestor of Unloop.
753         assert((NL != &Unloop && (!NL || NL->contains(&Unloop))) &&
754                "uninitialized successor");
755         LI->changeLoopFor(POI, NL);
756       } else {
757         // Or the current block is part of a subloop, in which case its parent
758         // is unchanged.
759         assert((FoundIB || Unloop.contains(L)) && "uninitialized successor");
760       }
761     }
762   }
763   // Each irreducible loop within the unloop induces a round of iteration using
764   // the DFS result cached by Traversal.
765   bool Changed = FoundIB;
766   for (unsigned NIters = 0; Changed; ++NIters) {
767     assert(NIters < Unloop.getNumBlocks() && "runaway iterative algorithm");
768     (void)NIters;
769 
770     // Iterate over the postorder list of blocks, propagating the nearest loop
771     // from successors to predecessors as before.
772     Changed = false;
773     for (LoopBlocksDFS::POIterator POI = DFS.beginPostorder(),
774                                    POE = DFS.endPostorder();
775          POI != POE; ++POI) {
776 
777       Loop *L = LI->getLoopFor(*POI);
778       Loop *NL = getNearestLoop(*POI, L);
779       if (NL != L) {
780         assert(NL != &Unloop && (!NL || NL->contains(&Unloop)) &&
781                "uninitialized successor");
782         LI->changeLoopFor(*POI, NL);
783         Changed = true;
784       }
785     }
786   }
787 }
