802     for (Loop *OldParent = Unloop.getParentLoop(); OldParent != OuterParent;
803          OldParent = OldParent->getParentLoop()) {
804       assert(OldParent && "new loop is not an ancestor of the original");
805       OldParent->removeBlockFromLoop(BB);
806     }
807   }
